/* ===================================================
   HOME.CSS — UIverse Homepage Overrides & New Styles
   Import AFTER style.css
   =================================================== */

/* ---------- ROOT TOKENS ---------- */
:root {
  --accent: #eb6835;
  --accent-2: #6c5ce7;
  --accent-glow: rgba(235, 104, 53, 0.18);
  --sidebar-w: 240px;
  --navbar-h: 64px;
  --radius-lg: 20px;
  --radius-md: 14px;
  --radius-sm: 8px;
  --card-bg: #ffffff;
  --card-border: #ebebeb;
  --body-bg: #f5f4f2;
  --text-primary: #111;
  --text-secondary: #666;
  --font-heading: 'Syne', sans-serif;
  --font-body: 'DM Sans', sans-serif;
  --transition: 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Dark mode vars */
body.dark-mode {
  --card-bg: #1a1a1e;
  --card-border: #2a2a30;
  --body-bg: #0f0f12;
  --text-primary: #f0f0f0;
  --text-secondary: #999;
}

/* ---------- BASE RESET ---------- */
*, *::before, *::after {
  box-sizing: border-box;
}

html, body {
  height: auto;
  padding: 0;
  margin: 0;
  font-family: var(--font-body);
  background-color: var(--body-bg);
  color: var(--text-primary);
  transition: background-color 0.3s, color 0.3s;
}

/* ---------- TYPOGRAPHY ---------- */
h1, h2, h3 {
  font-family: var(--font-heading);
  margin: 0;
}

/* ============================================================
   SIDEBAR
   ============================================================ */
.sidebar {
  width: var(--sidebar-w);
  height: 100vh;
  background: linear-gradient(160deg, #141428 0%, #1c1c35 100%);
  display: flex;
  flex-direction: column;
  padding: 0;
  position: fixed;
  top: 0;
  left: 0;
  z-index: 1050;
  border-right: 1px solid rgba(255,255,255,0.05);
  transition: transform var(--transition);
}

.sidebar-brand {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 22px 24px;
  border-bottom: 1px solid rgba(255,255,255,0.06);
}

.brand-icon {
  font-size: 24px;
  color: var(--accent);
}

.brand-text {
  font-family: var(--font-heading);
  font-weight: 800;
  font-size: 20px;
  color: #fff;
  letter-spacing: -0.5px;
}

.sidebar-nav {
  flex: 1;
  overflow-y: auto;
  padding: 16px 12px;
}

.sidebar-nav ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.sidebar-nav li a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 11px 14px;
  color: #8a9bc0;
  text-decoration: none;
  border-radius: var(--radius-sm);
  font-size: 14px;
  font-weight: 500;
  transition: all var(--transition);
}

.sidebar-nav li a i {
  width: 18px;
  text-align: center;
  font-size: 15px;
}

.sidebar-nav li a:hover {
  background: rgba(255,255,255,0.07);
  color: #fff;
  transform: translateX(3px);
}

.sidebar-nav li.active a {
  background: linear-gradient(90deg, rgba(235,104,53,0.2) 0%, rgba(235,104,53,0.05) 100%);
  color: var(--accent);
  border-left: 3px solid var(--accent);
}

.sidebar-footer {
  padding: 20px 24px;
  border-top: 1px solid rgba(255,255,255,0.06);
  display: flex;
  gap: 16px;
}

.sidebar-footer a {
  color: #6a7a94;
  font-size: 16px;
  transition: color var(--transition);
}

.sidebar-footer a:hover {
  color: var(--accent);
}

/* Sidebar backdrop (mobile) */
.sidebar-backdrop {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  z-index: 1040;
  backdrop-filter: blur(2px);
}

.sidebar-backdrop.visible {
  display: block;
}

/* ============================================================
   NAVBAR
   ============================================================ */
.navbar {
  position: fixed;
  top: 0;
  left: var(--sidebar-w);
  right: 0;
  height: var(--navbar-h);
  background: rgba(245, 244, 242, 0.85);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 0 24px;
  z-index: 1000;
  border-bottom: 1px solid rgba(0,0,0,0.06);
  transition: all var(--transition);
}

body.dark-mode .navbar {
  background: rgba(15, 15, 18, 0.85);
  border-bottom-color: rgba(255,255,255,0.05);
}

.navbar.scrolled {
  height: 54px;
  box-shadow: 0 4px 24px rgba(0,0,0,0.08);
}

.menu-toggle {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 18px;
  color: var(--text-primary);
  padding: 6px;
  border-radius: 8px;
  display: none;
  transition: background var(--transition);
}

.menu-toggle:hover {
  background: rgba(0,0,0,0.06);
}

.navbar .logo {
  font-family: var(--font-heading);
  font-weight: 800;
  font-size: 20px;
  color: var(--accent);
  display: none;
  letter-spacing: -0.5px;
}

.search-bar {
  flex: 1;
  max-width: 420px;
  display: flex;
  align-items: center;
  gap: 8px;
  background: #fff;
  border: 1px solid var(--card-border);
  border-radius: 40px;
  padding: 8px 16px;
  margin: 0 auto;
  box-shadow: none;
  transition: all var(--transition);
}

body.dark-mode .search-bar {
  background: #1e1e24;
  border-color: var(--card-border);
}

.search-bar:focus-within {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-glow);
}

.search-icon {
  color: #aaa;
  font-size: 13px;
}

.search-bar input {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--font-body);
  font-size: 14px;
  color: var(--text-primary);
}

.search-bar input::placeholder {
  color: #aaa;
}

.search-kbd {
  font-size: 11px;
  background: #f0f0f0;
  color: #999;
  padding: 2px 6px;
  border-radius: 4px;
  font-family: monospace;
  white-space: nowrap;
}

body.dark-mode .search-kbd {
  background: #2a2a32;
  color: #666;
}

.nav-right {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-left: auto;
}

.nav-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  border-radius: 40px;
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: all var(--transition);
  white-space: nowrap;
}

.outline-nav-btn {
  background: transparent;
  border: 1px solid var(--card-border);
  color: var(--text-primary);
}

.outline-nav-btn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.primary-nav-btn {
  background: var(--accent);
  border: 1px solid var(--accent);
  color: #fff;
}

.primary-nav-btn:hover {
  background: #d45c28;
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(235,104,53,0.3);
}

.theme-toggle {
  background: none;
  border: 1px solid var(--card-border);
  width: 36px;
  height: 36px;
  border-radius: 50%;
  cursor: pointer;
  font-size: 14px;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition);
}

.theme-toggle:hover {
  border-color: var(--accent);
  color: var(--accent);
}

/* ============================================================
   MAIN LAYOUT
   ============================================================ */
.main-home {
  margin-left: var(--sidebar-w);
  margin-top: var(--navbar-h);
  padding: 40px 40px 0;
  min-height: calc(100vh - var(--navbar-h));
  display: flex;
  flex-direction: column;
  gap: 60px;
}

/* ============================================================
   HERO SECTION
   ============================================================ */
.hero {
  position: relative;
  background: linear-gradient(135deg, #fff 60%, #fff7f4 100%);
  border: 1px solid var(--card-border);
  border-radius: var(--radius-lg);
  padding: 72px 60px;
  text-align: center;
  overflow: hidden;
  margin-bottom: 0;
}

body.dark-mode .hero {
  background: linear-gradient(135deg, #1a1a1e 60%, #1e1614 100%);
  border-color: var(--card-border);
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 16px;
  background: rgba(235,104,53,0.1);
  color: var(--accent);
  border: 1px solid rgba(235,104,53,0.25);
  border-radius: 40px;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 28px;
  letter-spacing: 0.3px;
}

.hero-title {
  font-size: clamp(36px, 5vw, 60px);
  font-weight: 800;
  line-height: 1.1;
  letter-spacing: -2px;
  color: var(--text-primary);
  margin-bottom: 20px;
}

.hero-accent {
  background: linear-gradient(90deg, var(--accent) 0%, #f0a07a 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-desc {
  max-width: 560px;
  margin: 0 auto 36px;
  font-size: 16px;
  line-height: 1.7;
  color: var(--text-secondary);
}

.hero-actions {
  display: flex;
  justify-content: center;
  gap: 14px;
  flex-wrap: wrap;
  margin-bottom: 48px;
}

.btn-primary {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 13px 28px;
  background: var(--accent);
  color: #fff;
  border-radius: 40px;
  font-size: 15px;
  font-weight: 600;
  text-decoration: none;
  transition: all var(--transition);
  box-shadow: 0 4px 16px rgba(235,104,53,0.25);
}

.btn-primary:hover {
  background: #d45c28;
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(235,104,53,0.35);
}

.btn-ghost {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 13px 28px;
  background: transparent;
  color: var(--text-primary);
  border: 1.5px solid var(--card-border);
  border-radius: 40px;
  font-size: 15px;
  font-weight: 600;
  text-decoration: none;
  transition: all var(--transition);
}

.btn-ghost:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.hero-stats {
  display: inline-flex;
  align-items: center;
  gap: 0;
  background: rgba(0,0,0,0.04);
  border: 1px solid var(--card-border);
  border-radius: 40px;
  padding: 12px 32px;
  flex-wrap: wrap;
  gap: 4px;
}

body.dark-mode .hero-stats {
  background: rgba(255,255,255,0.04);
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 0 24px;
}

.stat-number {
  font-family: var(--font-heading);
  font-size: 22px;
  font-weight: 800;
  color: var(--accent);
  line-height: 1;
}

.stat-label {
  font-size: 11px;
  color: var(--text-secondary);
  margin-top: 3px;
  white-space: nowrap;
}

.stat-divider {
  width: 1px;
  height: 32px;
  background: var(--card-border);
}

/* Orbs */
.hero-orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
}

.orb-1 {
  width: 350px;
  height: 350px;
  background: radial-gradient(circle, rgba(235,104,53,0.12) 0%, transparent 70%);
  top: -100px;
  right: -80px;
}

.orb-2 {
  width: 250px;
  height: 250px;
  background: radial-gradient(circle, rgba(108,92,231,0.1) 0%, transparent 70%);
  bottom: -60px;
  left: -40px;
}

/* ============================================================
   SECTIONS COMMON
   ============================================================ */
.section {
  display: flex;
  flex-direction: column;
  gap: 32px;
  margin-bottom: 0;
}

.section-header {
  text-align: center;
}

.section-tag {
  display: inline-block;
  padding: 4px 14px;
  background: rgba(235,104,53,0.1);
  color: var(--accent);
  border-radius: 40px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: uppercase;
  margin-bottom: 10px;
}

.section-title {
  font-size: clamp(22px, 3vw, 30px);
  font-weight: 800;
  color: var(--text-primary);
  letter-spacing: -0.8px;
  margin-bottom: 6px;
}

.section-subtitle {
  font-size: 15px;
  color: var(--text-secondary);
  margin: 0;
}

/* ============================================================
   FEATURED CARDS
   ============================================================ */
.featured-cards {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 20px;
}

.feature-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--radius-md);
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: all var(--transition);
  opacity: 0;
  transform: translateY(20px);
}

.feature-card.in-view {
  opacity: 1;
  transform: translateY(0);
}

.feature-card:hover {
  transform: translateY(-6px);
  box-shadow: 0 20px 40px rgba(0,0,0,0.08);
  border-color: rgba(235,104,53,0.3);
}

body.dark-mode .feature-card:hover {
  box-shadow: 0 20px 40px rgba(0,0,0,0.3);
}

.feature-icon-wrap {
  width: 48px;
  height: 48px;
  border-radius: 14px;
  background: color-mix(in srgb, var(--icon-color) 15%, transparent);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}

.feature-card-body h3 {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 4px;
}

.feature-card-body p {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.5;
  margin: 0;
}

.feature-tags {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-top: 4px;
}

.tag {
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
}

.tag-popular   { background: rgba(116,185,255,0.15); color: #0984e3; }
.tag-trending  { background: rgba(253,121,168,0.15); color: #e84393; }
.tag-new       { background: rgba(0,184,148,0.15);  color: #00b894; }
.tag-essential { background: rgba(253,203,110,0.15); color: #e17055; }

.feature-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  font-weight: 600;
  color: var(--accent);
  text-decoration: none;
  margin-top: auto;
  transition: gap var(--transition);
}

.feature-link:hover {
  gap: 10px;
}

/* ============================================================
   CATEGORIES GRID
   ============================================================ */
.categories-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 16px;
}

.cat-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--radius-md);
  padding: 24px 16px 20px;
  text-align: center;
  text-decoration: none;
  color: var(--text-primary);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  transition: all var(--transition);
  opacity: 0;
  transform: translateY(20px);
}

.cat-card.in-view {
  opacity: 1;
  transform: translateY(0);
}

.cat-card:hover {
  border-color: var(--accent);
  transform: translateY(-5px);
  box-shadow: 0 12px 28px rgba(0,0,0,0.07);
}

.cat-icon {
  font-size: 28px;
  margin-bottom: 4px;
}

.cat-card h3 {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-primary);
}

.cat-card p {
  font-size: 12px;
  color: var(--text-secondary);
  margin: 0;
  line-height: 1.4;
}

.cat-count {
  font-size: 11px;
  color: var(--accent);
  font-weight: 600;
  background: rgba(235,104,53,0.1);
  padding: 2px 10px;
  border-radius: 20px;
  margin-top: 4px;
}

/* ============================================================
   WHY UIVERSE GRID
   ============================================================ */
.why-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 20px;
}

.why-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--radius-md);
  padding: 28px 24px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: all var(--transition);
  opacity: 0;
  transform: translateY(20px);
}

.why-card.in-view {
  opacity: 1;
  transform: translateY(0);
}

.why-card:hover {
  border-color: rgba(235,104,53,0.3);
  transform: translateY(-4px);
  box-shadow: 0 12px 30px rgba(0,0,0,0.07);
}

.why-icon {
  font-size: 26px;
  width: 50px;
  height: 50px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(235,104,53,0.08);
  border-radius: 14px;
}

.why-card h3 {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
}

.why-card p {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.6;
  margin: 0;
}

/* ============================================================
   CTA BANNER
   ============================================================ */
.cta-banner {
  position: relative;
  background: linear-gradient(130deg, #eb6835 0%, #c0442e 50%, #6c5ce7 100%);
  border-radius: var(--radius-lg);
  padding: 64px 48px;
  text-align: center;
  overflow: hidden;
  color: #fff;
}

.cta-content {
  position: relative;
  z-index: 2;
}

.cta-content h2 {
  font-size: clamp(24px, 4vw, 38px);
  font-weight: 800;
  margin-bottom: 12px;
  letter-spacing: -1px;
}

.cta-content p {
  font-size: 16px;
  opacity: 0.85;
  margin-bottom: 32px;
  max-width: 480px;
  margin-left: auto;
  margin-right: auto;
}

.cta-content .btn-primary {
  background: #fff;
  color: var(--accent);
  box-shadow: 0 4px 20px rgba(0,0,0,0.2);
}

.cta-content .btn-primary:hover {
  background: #f5f5f5;
  transform: translateY(-2px);
  box-shadow: 0 8px 28px rgba(0,0,0,0.25);
}

.cta-orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
}

.cta-orb-1 {
  width: 300px;
  height: 300px;
  background: rgba(255,255,255,0.1);
  top: -100px;
  right: -60px;
}

.cta-orb-2 {
  width: 200px;
  height: 200px;
  background: rgba(255,255,255,0.08);
  bottom: -80px;
  left: 80px;
}

/* ============================================================
   SCROLL TO TOP BUTTON
   ============================================================ */
#scrollTopBtn {
  position: fixed;
  bottom: 28px;
  right: 28px;
  width: 44px;
  height: 44px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 15px;
  cursor: pointer;
  z-index: 999;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 4px 16px rgba(235,104,53,0.35);
  opacity: 0;
  transform: translateY(12px);
  pointer-events: none;
  transition: all var(--transition);
}

#scrollTopBtn.visible {
  opacity: 1;
  transform: translateY(0);
  pointer-events: all;
}

#scrollTopBtn:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(235,104,53,0.45);
}

/* ============================================================
   FOOTER
   ============================================================ */
.footer {
  margin-left: var(--sidebar-w);
  background: #111;
  color: #aaa;
  padding: 0;
  margin-top: 60px;
}

.footer-container {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr 2fr;
  gap: 40px;
  padding: 56px 48px 40px;
  max-width: 100%;
}

.footer-logo {
  font-family: var(--font-heading);
  font-size: 20px;
  font-weight: 800;
  color: var(--accent);
  margin-bottom: 12px;
}

.footer-col p {
  font-size: 14px;
  line-height: 1.7;
  margin: 0 0 16px;
}

.footer-col h3 {
  font-family: var(--font-heading);
  font-size: 13px;
  font-weight: 700;
  color: #fff;
  letter-spacing: 0.8px;
  text-transform: uppercase;
  margin-bottom: 16px;
}

.footer-col ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.footer-col ul li a {
  color: #888;
  text-decoration: none;
  font-size: 14px;
  transition: color var(--transition);
}

.footer-col ul li a:hover {
  color: var(--accent);
}

.socials {
  display: flex;
  gap: 12px;
}

.socials a {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  background: #1e1e1e;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #888;
  text-decoration: none;
  font-size: 14px;
  transition: all var(--transition);
}

.socials a:hover {
  background: var(--accent);
  color: #fff;
  transform: translateY(-2px);
}

.newsletter-form {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin-top: 12px;
}

.newsletter-form input {
  flex: 1;
  min-width: 0;
  padding: 10px 14px;
  background: #1e1e1e;
  border: 1px solid #2a2a2a;
  border-radius: var(--radius-sm);
  color: #fff;
  font-size: 13px;
  outline: none;
  transition: border-color var(--transition);
}

.newsletter-form input:focus {
  border-color: var(--accent);
}

.newsletter-form button {
  padding: 10px 18px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: background var(--transition);
}

.newsletter-form button:hover {
  background: #d45c28;
}

.footer-bottom {
  border-top: 1px solid #1e1e1e;
  padding: 20px 48px;
  text-align: center;
  font-size: 13px;
  color: #555;
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 1024px) {
  .footer-container {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 768px) {
  :root { --sidebar-w: 0px; }

  .sidebar {
    transform: translateX(-240px);
    width: 240px;
  }

  .sidebar.open {
    transform: translateX(0);
  }

  .menu-toggle {
    display: flex;
  }

  .navbar .logo {
    display: block;
  }

  .main-home {
    padding: 24px 20px 0;
    gap: 40px;
  }

  .hero {
    padding: 48px 24px;
  }

  .hero-stats {
    gap: 0;
  }

  .stat {
    padding: 0 16px;
  }

  .footer {
    margin-left: 0;
  }

  .footer-container {
    grid-template-columns: 1fr;
    padding: 40px 24px;
    gap: 28px;
  }

  .footer-bottom {
    padding: 16px 24px;
  }

  .nav-btn {
    display: none;
  }
}

@media (max-width: 480px) {
  .hero-stats {
    flex-direction: column;
    border-radius: 16px;
    padding: 20px;
    gap: 16px;
  }

  .stat-divider {
    width: 80%;
    height: 1px;
  }

  .stat {
    flex-direction: row;
    gap: 8px;
  }

  .categories-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

/* SMOOTH SCROLLING */
html {
  scroll-behavior: smooth;
}

:root {
  --sidebar-width: 240px;

  /* Light Mode Color Palette */
  --bg-primary: #f3f4f7;
  --bg-secondary: #ffffff;
  --text-primary: #000000;
  --text-secondary: #1e1d1d9a;
  --text-tertiary: #666666;
  --border-color: #e5e7eb;
  --card-bg: #ffffff;
  --card-border: #e5e7eb;
  --card-shadow: rgba(0, 0, 0, 0.1);
  --button-bg: #883f12;
  --button-hover: #f0ac45;
  --code-bg: #ffffff;
  --code-color: #000000;
  --link-color: #0066cc;
  --link-hover: #003d99;
  --header-bg: #ffffff;
  --header-border: #e5e7eb;
  --sidebar-bg: #ffffff;
  --sidebar-text: #1e1d1d;
  --sidebar-hover-bg: #f0f0f0;
  --input-bg: #ffffff;
  --input-border: #d0d0d0;
  --input-text: #000000;
  --accent-color: #eb6839;
}

html.dark-mode {
  --bg-primary: #0f172a;
  --bg-secondary: #1a1f2e;
  --text-primary: #e5e7eb;
  --text-secondary: #cbd5e1;
  --text-tertiary: #94a3b8;
  --border-color: #334155;
  --card-bg: #1e293b;
  --card-border: #334155;
  --card-shadow: rgba(0, 0, 0, 0.3);
  --button-bg: #475569;
  --button-hover: #64748b;
  --code-bg: #020617;
  --code-color: #38bdf8;
  --link-color: #60a5fa;
  --link-hover: #93c5fd;
  --header-bg: #0f172a;
  --header-border: #334155;
  --sidebar-bg: #020617;
  --sidebar-text: #e5e7eb;
  --sidebar-hover-bg: #1e293b;
  --input-bg: #1e293b;
  --input-border: #475569;
  --input-text: #e5e7eb;
  --accent-color: #fb923c;
}

*, *::before, *::after {
  box-sizing: border-box;
}

/* RESET */
html, body {
  min-height: 100%;
  margin: 0;
  font-family: Arial, sans-serif;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  transition: background-color 0.3s ease, color 0.3s ease;
  padding: 20px;
  overflow-x: hidden;
}

body {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  background-color: var(--bg-primary);
}

h1 {
  color: rgb(235, 104, 57);
}

h3 {
  color: rgb(226, 133, 99);
}

/*navbar*/

nav {
  padding: 12px 16px;
}

/* simple navbar */
.nav-simple {
  display: flex;
  justify-content: space-between;
  align-items: center;
  position: relative;
}

.nav-links {
  display: flex;
  gap: 20px;
}

/* links */
nav a {
  text-decoration: none;
  color: #1e1d1d9a;
  font-weight: 500; 
  transition: 0.3s;
}

nav a:hover {
  color: orangered;
  transform: translateY(-2px);
}

/* btn nav */
.nav-btn {
  display: flex;
  overflow:hidden;
  justify-content: space-between;
  align-items: center;
}

.nav-btn button {
  padding: 6px 14px;
  border: none;
  background: #883f12;
  color: white;
  border-radius: 6px;
  cursor: pointer;
  transition: 0.3s;
}

.nav-btn button:hover {
  background: #f0ac45;
}

/* center navbar */
.nav-center {
  display: flex;
  justify-content: center;
  gap: 30px;
}

/* Responsive */
@media (max-width: 310px) {
  .nav-links {
    position: absolute;
    top: 50px;
    right: 0;
    background: white;
    flex-direction: column;
    width: 150px;
    padding: 10px;
    border-radius: 10px;
    box-shadow: 0 10px 20px rgba(0,0,0,0.1);
    display: none;
  }
}

