/* Badges */
.badge {
  display: inline-block;
  padding: 4px 8px;
  font-size: 12px;
  font-weight: 500;
  border-radius: 4px;
  text-align: center;
  line-height: 1;
}

.badge-pill {
  background: #6c5ce7;
  color: white;
  border-radius: 12px;
  padding: 6px 12px;
}

.badge-dot {
  background: #00b894;
  color: white;
  position: relative;
  padding-left: 20px;
}

.badge-dot::before {
  content: '';
  position: absolute;
  left: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 6px;
  height: 6px;
  background: white;
  border-radius: 50%;
}

.badge-count {
  background: #ff6b6b;
  color: white;
  border-radius: 50%;
  min-width: 20px;
  height: 20px;
  padding: 0 6px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* Badge Variations */
.badge-success {
  background: #00b894;
}

.badge-warning {
  background: #fdcb6e;
  color: #333;
}

.badge-danger {
  background: #e17055;
}

.badge-info {
  background: #74b9ff;
}

.badge-small {
  font-size: 10px;
  padding: 4px 8px;
}

.badge-large {
  font-size: 14px;
  padding: 8px 16px;
}

.badge-outlined {
  background: transparent;
  border: 2px solid #6c5ce7;
  color: #6c5ce7;
}

.badge-notification {
  background: #e17055;
  position: relative;
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0% { transform: scale(1); }
  50% { transform: scale(1.1); }
  100% { transform: scale(1); }
}

/* ================= ALERTS ================= */

.alert-box {
  padding: 16px;
  border-radius: 8px;
  margin-bottom: 16px;
  border: 1px solid transparent;
  display: flex;
  align-items: flex-start;
  gap: 12px;
  font-size: 14px;
  line-height: 1.5;
  box-sizing: border-box;
}

.alert-box strong {
  display: block;
  margin-bottom: 4px;
  font-weight: 600;
}

.alert-box p {
  margin: 0;
}

/* Alert Types */
.alert-success {
  background-color: #d4edda;
  border-color: #c3e6cb;
  color: #155724;
}

.alert-success strong {
  color: #155724;
}

.alert-warning {
  background-color: #fff3cd;
  border-color: #ffeaa7;
  color: #856404;
}

.alert-warning strong {
  color: #856404;
}

.alert-error {
  background-color: #f8d7da;
  border-color: #f5c6cb;
  color: #721c24;
}

.alert-error strong {
  color: #721c24;
}

.alert-info {
  background-color: #d1ecf1;
  border-color: #bee5eb;
  color: #0c5460;
}

.alert-info strong {
  color: #0c5460;
}

.alert-critical {
  background-color: #f8b5bb;
  border-color: #e74c3c;
  color: #721c24;
  animation: critical-pulse 1.5s ease-in-out infinite;
}

.alert-critical strong {
  color: #721c24;
}

@keyframes critical-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.8; }
}

.alert-pending {
  background-color: #e8f4f8;
  border-color: #b8dce8;
  color: #2c5aa0;
}

.alert-pending strong {
  color: #2c5aa0;
}

/* Alert Variants */
.alert-dismissible {
  position: relative;
}

.alert-close {
  position: absolute;
  right: 12px;
  top: 12px;
  background: none;
  border: none;
  font-size: 20px;
  cursor: pointer;
  padding: 0;
  color: inherit;
  opacity: 0.7;
  transition: opacity 0.3s ease;
}

.alert-close:hover {
  opacity: 1;
}

.alert-with-icon {
  align-items: center;
}

.alert-icon {
  font-size: 20px;
  flex-shrink: 0;
}

.alert-compact {
  padding: 12px 16px;
  font-size: 13px;
}

.alert-compact p {
  display: none;
}

.alert-left-border {
  border-left: 4px solid;
  border-right: none;
}

.alert-success.alert-left-border {
  border-left-color: #155724;
}

  display: flex;
