   ===================== */
.toast {
  position: fixed;
  bottom: 32px;
  right: 32px;
  background: #222;
  color: #fff;
  padding: 12px 22px;
  border-radius: 8px;
  font-size: 0.95rem;
  font-family: Arial, sans-serif;
  box-shadow: 0 4px 18px rgba(0, 0, 0, 0.22);
  z-index: 9999;
  opacity: 0;
  transform: translateY(16px);
  transition: opacity 0.3s ease, transform 0.3s ease;
  pointer-events: none;
}

.toast.toast-visible {
  opacity: 1;
  transform: translateY(0);
}

.toast.toast-hidden {
  opacity: 0;
  transform: translateY(16px);
}

