  border-radius: 12px;

  text-decoration: none;
  font-size: 1.2rem;

  transition: 0.3s ease;
}

.socials a:hover{
  transform: translateY(-5px) scale(1.05);

  background: #7c3aed;

  box-shadow: 0 10px 25px rgba(124,58,237,0.35);
}

/* FOOTER */

.footer{
  margin-top: 80px;
  background: #0f172a;
  color: white;
  padding: 60px 8%;
}

.footer-container{
  display: grid;
  grid-template-columns: repeat(auto-fit,minmax(220px,1fr));
  gap: 40px;
}

.footer-col h2{
  font-size: 2rem;
  margin-bottom: 15px;
}

.footer-col h3{
  margin-bottom: 18px;
  font-size: 1.2rem;
}

.footer-col p{
  color: rgba(255,255,255,0.7);
  line-height: 1.7;
}

.footer-col a{
  display: block;
  margin-bottom: 12px;
  color: rgba(255,255,255,0.75);
  text-decoration: none;
  transition: 0.3s ease;
}

.footer-col a:hover{
  color: #a855f7;
  transform: translateX(5px);
}

/* SOCIAL ICONS */

.socials{
  display: flex;
  gap: 15px;
  margin-top: 20px;
}

.socials a{
  width: 48px;
  height: 48px;

  display: flex;
  align-items: center;
  justify-content: center;

  border-radius: 14px;

  background: rgba(255,255,255,0.08);

  border: 1px solid rgba(255,255,255,0.08);

  text-decoration: none;

  font-size: 1.2rem;

  transition: all 0.35s ease;

  backdrop-filter: blur(10px);
}

.socials a:hover{
  transform: translateY(-6px) scale(1.08);

  background: linear-gradient(
    135deg,
    #7c3aed,
    #a855f7
  );

  box-shadow:
    0 10px 25px rgba(124,58,237,0.35),
    0 0 20px #a855f740;
}
.nav-section {
  margin-top: 18px;
  margin-bottom: 6px;
  font-size: 12px;
  font-weight: 600;
  color: #94a3b8;
  text-transform: uppercase;
  letter-spacing: 1px;
  padding-left: 10px;
}

/* =========================
   RESPONSIVE UIVERSE SYSTEM
   ========================= */

/* Tablets */
@media (max-width: 1024px) {

  .container {
    flex-direction: column;
  }

  .sidebar {
    width: 100%;
    position: relative;
    height: auto;
  }

  .main {
    padding: 20px;
  }

  .features {
    grid-template-columns: repeat(2, 1fr);
  }

  .hero h1 {
    font-size: 32px;
  }
}

/* Mobile */
@media (max-width: 768px) {

  /* Sidebar becomes top nav */
  .sidebar {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    padding: 15px;
  }

  .sidebar nav ul {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
  }

  .sidebar nav ul li {
    font-size: 13px;
  }

  /* Main spacing */
  .main {
    padding: 15px;
  }

  /* Hero */
  .hero {
    text-align: left;
    padding: 20px 10px;
  }

  .hero h1 {
    font-size: 26px;
  }

  .hero p {
    font-size: 14px;
  }

  /* Feature grid → single column */
  .features {
    grid-template-columns: 1fr;
  }

  /* Buttons stack */
  .hero-buttons {
    display: flex;
    flex-direction: column;
    gap: 10px;
  }

  .primary-btn,
  .secondary-btn {
    width: 100%;
    text-align: center;
  }
}

/* Extra small devices */
@media (max-width: 480px) {

  .hero h1 {
    font-size: 22px;
  }

  .sidebar h2 {
    font-size: 18px;
  }

  .feature-card {
    padding: 15px;
  }

}
.menu-toggle {
  display: none;
  background: none;
  border: none;
  font-size: 22px;
  color: white;
  cursor: pointer;
}

@media (max-width: 768px) {
  .menu-toggle {
    display: block;
  }

  .sidebar nav {
    display: none;
  }

  .sidebar.active nav {
    display: block;
    width: 100%;
  }
}
.card {
  transition: all 0.3s ease;
  cursor: pointer;
}

.card:hover {
  transform: translateY(-8px);
  box-shadow: 0 10px 25px rgba(0,0,0,0.1);
}
/* ── Category Filter Search ── */
.cat-search-wrap {
  position: relative;
  max-width: 420px;
  margin: 0 auto 1.75rem;
  display: flex;
  align-items: center;
}
.cat-search-icon {
  position: absolute;
  left: 1rem;
  color: #9ca3af;
  font-size: .85rem;
  pointer-events: none;
}
#catSearch {
  width: 100%;
  padding: .7rem 2.5rem .7rem 2.75rem;
  border: 1.5px solid #e4e7ec;
  border-radius: 10px;
  font-size: .9rem;
  font-family: inherit;
  background: #f8f9fb;
  color: #111827;
  outline: none;
  transition: border-color .2s, box-shadow .2s;
}
#catSearch:focus {
  border-color: #6366f1;
  box-shadow: 0 0 0 3px rgba(99,102,241,.12);
  background: #fff;
}
.dark-mode #catSearch {
  background: #1a1d27;
  border-color: #2d3249;
  color: #f1f5f9;
}
.cat-clear {
  position: absolute;
  right: .85rem;
  cursor: pointer;
  color: #9ca3af;
  font-size: .85rem;
  display: none;
}
.cat-clear:hover { color: #6366f1; }
.cat-no-result {
  text-align: center;
  color: #9ca3af;
  font-size: .9rem;
  margin-top: -.5rem;
  margin-bottom: 1rem;
}
.hidden { display: none; }
.cat-card.hide { display: none; }
